import { useState, useContext, useEffect } from "react";
// import axios from "../api/axios";
import { AuthContext } from "../context/AuthContext";
import StudyRoom from "../components/StudyRoom";

const Dashboard = () => {
    const { token } = useContext(AuthContext);
    const [syllabus, setSyllabus] = useState("");
    const [examDate, setExamDate] = useState("");
    const [tasks, setTasks] = useState([]);
    const [activeTask, setActiveTask] = useState(null); // Tracks current study session

    // Fetch tasks on initial load
    useEffect(() => {
        if (token) fetchTasks();
    }, [token]);

    const fetchTasks = async () => {
        try {
            const res = await axios.get("http://localhost:5000/api/tasks", {
                headers: { Authorization: `Bearer ${token}` }
            });
            setTasks(res.data);
        } catch (err) {
            console.error("Error fetching tasks:", err);
        }
    };

    const handleCreatePlan = async () => {
        try {
            await axios.post("http://localhost:5000/api/plan/create", 
                { syllabus, examDate },
                { headers: { Authorization: `Bearer ${token}` } }
            );
            alert("AI has generated your timetable!");
            fetchTasks();
        } catch (err) {
            console.error("Error creating plan:", err);
        }
    };

    const handleCompleteTask = async (taskId) => {
        try {
            await axios.put(`http://localhost:5000/api/tasks/${taskId}`, 
                { status: "completed" },
                { headers: { Authorization: `Bearer ${token}` } }
            );
            alert("Topic marked as completed! Your AI Pulse is strong.");
            setActiveTask(null); // Return to dashboard
            fetchTasks(); // Refresh list
        } catch (err) {
            console.error("Error updating task:", err);
        }
    };

    // If a student is actively studying, show only the StudyRoom
    if (activeTask) {
        return (
            <div className="min-h-screen bg-gray-50 p-5">
                <button 
                    onClick={() => setActiveTask(null)} 
                    className="mb-4 text-blue-600 underline"
                >
                    ← Back to Schedule
                </button>
                <StudyRoom task={activeTask} onComplete={handleCompleteTask} />
            </div>
        );
    }

    return (
        <div className="p-10 max-w-4xl mx-auto">
            <h1 className="text-3xl font-bold mb-6 text-blue-800">StudyPulse Dashboard</h1>
            
            <div className="bg-white p-6 rounded-lg shadow-md mb-10">
                <h2 className="text-xl font-semibold mb-4">Generate New Study Plan</h2>
                <div className="flex flex-col gap-4">
                    <textarea 
                        placeholder="Enter chapters (e.g. React Hooks, Node.js Auth, MongoDB Aggregation)..."
                        onChange={(e) => setSyllabus(e.target.value)}
                        className="border-2 p-3 rounded-md focus:border-blue-500 outline-none h-32"
                    />
                    <div className="flex items-center gap-4">
                        <label className="font-medium">Exam Date:</label>
                        <input 
                            type="date" 
                            onChange={(e) => setExamDate(e.target.value)}
                            className="border p-2 rounded-md"
                        />
                    </div>
                    <button 
                        onClick={handleCreatePlan} 
                        className="bg-blue-600 hover:bg-blue-700 text-white font-bold py-3 rounded-md transition"
                    >
                        Ask AI to Schedule
                    </button>
                </div>
            </div>

            <div className="mt-10">
                <h2 className="text-2xl font-semibold mb-4">Your Smart Schedule</h2>
                <div className="grid gap-4">
                    {tasks.length > 0 ? tasks.map(task => (
                        <div key={task._id} className="bg-white border-l-4 border-blue-500 p-4 rounded shadow-sm flex justify-between items-center">
                            <div>
                                <h3 className="font-bold text-lg">{task.title}</h3>
                                <p className="text-gray-500">{new Date(task.date).toLocaleDateString()}</p>
                                <span className={`text-xs font-bold uppercase ${task.status === 'completed' ? 'text-green-500' : 'text-orange-500'}`}>
                                    {task.status}
                                </span>
                            </div>
                            {task.status !== 'completed' && (
                                <button 
                                    onClick={() => setActiveTask(task)}
                                    className="bg-green-500 hover:bg-green-600 text-white px-4 py-2 rounded-lg font-medium transition"
                                >
                                    Start Studying
                                </button>
                            )}
                        </div>
                    )) : (
                        <p className="text-gray-400 italic">No tasks yet. Enter your syllabus above!</p>
                    )}
                </div>
            </div>
        </div>
    );
};

export default Dashboard;
